// ProcessOverdueActionTasks finds all tasks whose overdue action grace period
// has elapsed and applies the configured action to each one. Any recurrence
// type may carry a rule (set_status and clear_due_date apply to one-off and
// on-dependency tasks too).

input.content:
package taskengine

import (
	"strings"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"

	dbgen "github.com/sargunv/tend/server/internal/database/gen"
)

func nullOverdueAction(a dbgen.OverdueAction) dbgen.NullOverdueAction {
	return dbgen.NullOverdueAction{OverdueAction: a, Valid: true}
}

func TestValidateOverdueActionRule(t *testing.T) {
	tests := []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}{
		// ─── No rule ─────────────────────────────────────────────────────────────────
		{
			name:           "nil rule always valid",
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        false,
		},
		// ─── Universal precondition ───────────────────────────────────────────────────
		{
			name:           "rule requires a due date",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},

		// ─── Behavior matrix (action × recurrence type, due present) ──────────────────
		// advance_recurrence: only completion_based and fixed_non_accumulating.
		{
			name:           "advance_recurrence on one_off rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "requires a scheduled recurrence",
		},
		{
			name:           "advance_recurrence on on_dependency rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        true,
			errContains:    "requires a scheduled recurrence",
		},
		{
			name:           "advance_recurrence on fixed_accumulating rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        true,
			errContains:    "not supported on fixed_accumulating",
		},
		{
			name:           "advance_recurrence on completion_based allowed",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "advance_recurrence on fixed_non_accumulating allowed",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		// set_status: valid on every recurrence type with a due date.
		{
			name:           "set_status on one_off allowed",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "skipped", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on on_dependency allowed",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "skipped", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on completion_based allowed",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "skipped", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on fixed_non_accumulating allowed",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "skipped", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "set_status on fixed_accumulating allowed",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "skipped", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		// clear_due_date: valid on every recurrence type with a due date.
		{
			name:           "clear_due_date on one_off allowed",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on on_dependency allowed",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on completion_based allowed",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on fixed_non_accumulating allowed",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "clear_due_date on fixed_accumulating allowed",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        false,
		},

		// ─── Action-specific shape requirements ───────────────────────────────────────
		{
			name:           "set_status without status name rejected",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateOverdueActionRule(tc.afterDays, tc.action, tc.statusName, tc.recurrenceType, tc.hasDue)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				if tc.errContains != "" && !strings.Contains(err.Error(), tc.errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), tc.errContains)
				}
			} else if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
		})
	}
}

